const helpers = this.helpers;

async function getJson(path, retries = 3, delayMs = 1000) {
  for (let attempt = 1; attempt <= retries; attempt++) {
    try {
      const response = await helpers.httpRequest({ method: 'GET', url: `http://mocks:8000${path}` });
      return typeof response === 'string' ? JSON.parse(response) : response;
    } catch (err) {
      if (attempt === retries) throw err;
      await new Promise(resolve => setTimeout(resolve, delayMs));
    }
  }
}

const customerId = query.trim();

const [salesforce, clm, netsuite, provisioning] = await Promise.all([
  getJson(`/salesforce/opportunities/${customerId}`),
  getJson(`/clm/contracts/${customerId}`),
  getJson(`/netsuite/invoices/${customerId}`),
  getJson(`/provisioning/status/${customerId}`),
]);

return JSON.stringify({ customer_id: customerId, salesforce, clm, netsuite, provisioning }, null, 2);

const helpers = this.helpers;

async function getJson(path, retries = 3, delayMs = 1000) {
  for (let attempt = 1; attempt <= retries; attempt++) {
    try {
      const response = await helpers.httpRequest({ method: 'GET', url: `http://mocks:8000${path}` });
      return typeof response === 'string' ? JSON.parse(response) : response;
    } catch (err) {
      if (attempt === retries) throw err;
      await new Promise(resolve => setTimeout(resolve, delayMs));
    }
  }
}

async function postJson(path, body) {
  const response = await helpers.httpRequest({
    method: 'POST',
    url: `http://mocks:8000${path}`,
    body,
    json: true,
  });
  return typeof response === 'string' ? JSON.parse(response) : response;
}

const params = typeof query === 'string' ? JSON.parse(query) : query;
const customerId = params.customer_id;
const confirmed = params.confirmed === true || params.confirmed === 'true';

const provisioning = await getJson(`/provisioning/status/${customerId}`);
const today = $now.toFormat('yyyy-LL-dd');

const eligibleSteps = provisioning.steps.filter(s =>
  s.owner === 'customer' && s.status !== 'done' && s.due_date < today
);

if (eligibleSteps.length === 0) {
  return JSON.stringify({
    draft: null,
    sent: false,
    message: `No overdue customer-owned provisioning steps for ${customerId}. Nothing to nudge.`,
  });
}

const message = `Hi! This is a friendly reminder that the following onboarding step(s) are still outstanding: ${eligibleSteps.map(s => `${s.name} (was due ${s.due_date})`).join(', ')}. Please complete these at your earliest convenience so we can keep your onboarding on track.`;

if (!confirmed) {
  return JSON.stringify({
    draft: message,
    eligible_steps: eligibleSteps.map(s => s.name),
    sent: false,
    note: 'This is a preview only. Nothing has been sent. Ask the user to confirm before calling again with confirmed=true.',
  });
}

const nudgeResult = await postJson('/provisioning/nudge', { customer_id: customerId, message });

await postJson('/audit', {
  run_id: `chat-${Date.now()}`,
  trigger: 'chat',
  customer_id: customerId,
  state_snapshot: { provisioning },
  llm_verdict: null,
  action_taken: nudgeResult.sent ? 'chat_nudge' : 'chat_nudge_skipped_already_sent',
});

return JSON.stringify({
  draft: message,
  eligible_steps: eligibleSteps.map(s => s.name),
  sent: nudgeResult.sent,
  nudge_id: nudgeResult.nudge_id,
  reason: nudgeResult.reason || null,
});
